import argparse
import json
import os
import re
import string
from collections import Counter

from tqdm import tqdm


def normalize_answer(s):
    """Lower text and remove punctuation, articles and extra whitespace."""

    def remove_articles(text):
        return re.sub(r"\b(a|an|the)\b", " ", text)

    def white_space_fix(text):
        return " ".join(text.split())

    def remove_punc(text):
        exclude = set(string.punctuation)
        return "".join(ch for ch in text if ch not in exclude)

    def lower(text):
        return text.lower()

    return white_space_fix(remove_articles(remove_punc(lower(s))))


def normalize_zh_answer(s):
    """Lower text and remove punctuation, extra whitespace."""

    def white_space_fix(text):
        return "".join(text.split())

    def remove_punc(text):
        cn_punctuation = "！？｡。＂＃＄％＆＇（）＊＋，－／：；＜＝＞＠［＼］＾＿｀｛｜｝～｟｠｢｣､、〃》「」『』【】〔〕〖〗〘〙〚〛〜〝〞〟〰〾〿–—‘’‛“”„‟…‧﹏."
        all_punctuation = set(string.punctuation + cn_punctuation)
        return "".join(ch for ch in text if ch not in all_punctuation)

    def lower(text):
        return text.lower()

    return white_space_fix(remove_punc(lower(s)))


def f1_score(prediction, ground_truth):
    common = Counter(prediction) & Counter(ground_truth)
    num_same = sum(common.values())
    if num_same == 0:
        return 0
    precision = 1.0 * num_same / len(prediction)
    recall = 1.0 * num_same / len(ground_truth)
    f1 = (2 * precision * recall) / (precision + recall)
    return f1


def qa_f1_score(pred, ground_truths):
    """Compute the F1 score of a prediction."""
    scores = []
    for ground_truth in ground_truths:
        normalized_prediction = normalize_answer(pred)
        normalized_ground_truth = normalize_answer(ground_truth)

        prediction_tokens = normalized_prediction.split()
        ground_truth_tokens = normalized_ground_truth.split()
        scores.append(f1_score(prediction_tokens, ground_truth_tokens))
    return max(scores)


def qa_f1_score_zh(pred, ground_truths):
    """
    pred: 模型回答
    ground_truths: 多个答案的列表
    """
    scores = []
    for ground_truth in ground_truths:
        normalized_pred = normalize_zh_answer(pred)
        normalized_ground_truth = normalize_zh_answer(ground_truth)

        prediction_tokens = set(normalized_pred)
        ground_truth_tokens = set(normalized_ground_truth)
        scores.append(f1_score(prediction_tokens, ground_truth_tokens))
    return max(scores)


def eval_file(args):
    dataset = args.dataset
    output_path = args.output_path
    output_data = [json.loads(line) for line in open(output_path, "r")]
    if dataset == "zh":
        acc = 0
        for i, data in enumerate(output_data):
            pred = data["pred"]
            ground_truths = data["ground_truth"]
            acc += qa_f1_score_zh(pred, ground_truths)
        return acc / len(output_data)

    elif dataset == "en":
        acc = 0
        for i, data in enumerate(output_data):
            pred = data["pred"]
            ground_truths = data["ground_truth"]
            acc += qa_f1_score(pred, ground_truths)
        return acc / len(output_data)
    elif dataset == "math":
        count = 0
        for i, data in enumerate(output_data):
            pred = data["pred"]
            ground_truth = data["ground_truth"]
            if pred == ground_truth:
                count += 1
        return count / len(output_data)


if __name__ == "__main__":
