    parser.add_argument(
        "--dataset",
        type=str,
        default="zh",
        help="dataset type, zh or en or math",
    )
    parser.add_argument(
        "--output_path",
        type=str,
        default="./pred.jsonl",
        help="path to the output file",
    )

